import{_ as e,o as a,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F18: 估值與決策綜合判斷框架","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/分析模式/估值與決策框架.md","filePath":"Deep32Q知識庫/分析模式/估值與決策框架.md"}'),s={name:"Deep32Q知識庫/分析模式/估值與決策框架.md"};function d(i,t,r,h,g,o){return a(),n("div",null,[...t[0]||(t[0]=[l(`<h1 id="f18-估值與決策綜合判斷框架" tabindex="-1">F18: 估值與決策綜合判斷框架 <a class="header-anchor" href="#f18-估值與決策綜合判斷框架" aria-label="Permalink to &quot;F18: 估值與決策綜合判斷框架&quot;">​</a></h1><blockquote><p><strong>適用範圍</strong>：所有上市櫃公司（跨產業通用分析模式） <strong>核心問題</strong>：綜合潛在風險、未來願景與籌碼面，公司當前的合理估值落於何種區間？本益比河流圖是否具備安全邊際？ <strong>最後更新</strong>：2026-04-25（基於良維 6290、瀚荃 8103 實例提煉）</p></blockquote><hr><h2 id="🏗️-框架總覽-五層估值金字塔" tabindex="-1">🏗️ 框架總覽：五層估值金字塔 <a class="header-anchor" href="#🏗️-框架總覽-五層估值金字塔" aria-label="Permalink to &quot;🏗️ 框架總覽：五層估值金字塔&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第5層 ── 決策執行建議（操作等級 + 買區 + 停損）</span></span>
<span class="line"><span>第4層 ── 評價位階對位（PE/PBR/DY 當前 vs 歷史）</span></span>
<span class="line"><span>第3層 ── 願景真偽審核（敘事是否有財務數據支撐）</span></span>
<span class="line"><span>第2層 ── 風險壓力測試（多情境 EPS × PE → 目標價區間）</span></span>
<span class="line"><span>第1層 ── 數據基石（股價、EPS、營收、籌碼面）</span></span></code></pre></div><p><strong>核心原則：好公司 ≠ 好價格。安全邊際是唯一的護城河。</strong></p><hr><h2 id="第一層-數據基石-data-foundation" tabindex="-1">第一層：數據基石（Data Foundation） <a class="header-anchor" href="#第一層-數據基石-data-foundation" aria-label="Permalink to &quot;第一層：數據基石（Data Foundation）&quot;">​</a></h2><h3 id="必填基礎數據" tabindex="-1">必填基礎數據 <a class="header-anchor" href="#必填基礎數據" aria-label="Permalink to &quot;必填基礎數據&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th>來源</th><th>用途</th></tr></thead><tbody><tr><td style="text-align:left;">當前股價</td><td>FinMind price API</td><td>估值計算基準</td></tr><tr><td style="text-align:left;">歷史 EPS（近3-5年）</td><td>FinMind finance API</td><td>PE 計算、成長率</td></tr><tr><td style="text-align:left;">歷史 PER/PBR</td><td>FinMind PER/PBR API</td><td>估值百分位、河流圖</td></tr><tr><td style="text-align:left;">月營收年增率（近12-24個月）</td><td>FinMind revenue API</td><td>成長動能確認</td></tr><tr><td style="text-align:left;">法人買賣超（近3-6個月）</td><td>FinMind institutional API</td><td>籌碼面趨勢</td></tr><tr><td style="text-align:left;">股權分散表（大戶佔比）</td><td>FinMind backer_holding API</td><td>籌碼集中度</td></tr><tr><td style="text-align:left;">現金股利歷史</td><td>FinMind dividend API</td><td>殖利率、股東回報</td></tr></tbody></table><h3 id="基礎計算" tabindex="-1">基礎計算 <a class="header-anchor" href="#基礎計算" aria-label="Permalink to &quot;基礎計算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>歷史 PE 區間 = 各期股價 ÷ 對應年度 EPS</span></span>
<span class="line"><span>合理 PE 區間 = 歷史中位數 ± 成長溢價調整</span></span>
<span class="line"><span>PEG = 當前 PE ÷ EPS 年複合成長率 (CAGR)</span></span>
<span class="line"><span>估值百分位 = 當前 PE 在歷史區間中的排名位置</span></span></code></pre></div><hr><h2 id="第二層-風險壓力測試-risk-stress-test" tabindex="-1">第二層：風險壓力測試（Risk Stress Test） <a class="header-anchor" href="#第二層-風險壓力測試-risk-stress-test" aria-label="Permalink to &quot;第二層：風險壓力測試（Risk Stress Test）&quot;">​</a></h2><h3 id="五情境模型" tabindex="-1">五情境模型 <a class="header-anchor" href="#五情境模型" aria-label="Permalink to &quot;五情境模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">情境</th><th style="text-align:right;">假設 EPS</th><th style="text-align:right;">適用 PE</th><th>目標價公式</th><th>使用時機</th></tr></thead><tbody><tr><td style="text-align:left;">激進樂觀</td><td style="text-align:right;">2026E EPS（+20%~30%）</td><td style="text-align:right;">歷史高點 + 溢價 (25-30x)</td><td>EPS × PE</td><td>市場共識極度樂觀時</td></tr><tr><td style="text-align:left;">穩健（合理估值上緣）</td><td style="text-align:right;">2026E EPS（+15%~20%）</td><td style="text-align:right;">歷史高點 (20-25x)</td><td>EPS × PE</td><td>成長動能確認中</td></tr><tr><td style="text-align:left;">中性（歷史中位數）</td><td style="text-align:right;">2025A EPS</td><td style="text-align:right;">歷史中位數 (14-18x)</td><td>EPS × PE</td><td>基準情境</td></tr><tr><td style="text-align:left;">悲觀（成長減速）</td><td style="text-align:right;">2026E EPS（-5%~10%）</td><td style="text-align:right;">歷史低點偏上 (12-14x)</td><td>EPS × PE</td><td>成長動能放緩時</td></tr><tr><td style="text-align:left;">極端保守</td><td style="text-align:right;">2026E EPS（-15%~20%）</td><td style="text-align:right;">歷史最低點 (10-12x)</td><td>EPS × PE</td><td>黑天鵝情境</td></tr></tbody></table><h3 id="壓力測試輸出格式" tabindex="-1">壓力測試輸出格式 <a class="header-anchor" href="#壓力測試輸出格式" aria-label="Permalink to &quot;壓力測試輸出格式&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 情境 | 假設 EPS | 適用 PE | 目標價 | 距現價跌幅 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|:---|---:|---:|---:|---:|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 激進樂觀 | X.XX | XXx | XXX元 | -XX% |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 穩健（合理估值上緣） | X.XX | XXx | XXX元 | -XX% |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 中性（歷史中位數） | X.XX | XXx | XXX元 | -XX% |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 悲觀（成長減速） | X.XX | XXx | XXX元 | -XX% |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 極端保守 | X.XX | XXx | XXX元 | -XX% |</span></span></code></pre></div><h3 id="安全邊際判定規則" tabindex="-1">安全邊際判定規則 <a class="header-anchor" href="#安全邊際判定規則" aria-label="Permalink to &quot;安全邊際判定規則&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">當前價格 vs 合理區間上緣</th><th style="text-align:right;">判定</th><th>操作指引</th></tr></thead><tbody><tr><td style="text-align:left;">低於合理區間下緣（-20%以下）</td><td style="text-align:right;">✅ 具安全邊際</td><td>分批建倉</td></tr><tr><td style="text-align:left;">落在合理區間內（±10%）</td><td style="text-align:right;">⚠️ 中性估值</td><td>觀望，等待回檔</td></tr><tr><td style="text-align:left;">高於合理區間上緣（+10%以上）</td><td style="text-align:right;">⚠️ 溢價估值</td><td>逢高減碼</td></tr><tr><td style="text-align:left;">高於合理區間上緣（+30%以上）</td><td style="text-align:right;">❌ 極端溢價</td><td>不宜追價，停損防線啟動</td></tr></tbody></table><hr><h2 id="第三層-願景真偽審核-vision-authenticity-audit" tabindex="-1">第三層：願景真偽審核（Vision Authenticity Audit） <a class="header-anchor" href="#第三層-願景真偽審核-vision-authenticity-audit" aria-label="Permalink to &quot;第三層：願景真偽審核（Vision Authenticity Audit）&quot;">​</a></h2><h3 id="審核框架-四維度驗證" tabindex="-1">審核框架：四維度驗證 <a class="header-anchor" href="#審核框架-四維度驗證" aria-label="Permalink to &quot;審核框架：四維度驗證&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">維度</th><th>檢查項目</th><th>判定標準</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>成長動能</strong></td><td>新產品/新市場佔比趨勢</td><td>有數據支撐（占比提升+營收貢獻）→ ✅；空洞敘事 → ❌</td></tr><tr><td style="text-align:left;"><strong>資本支出</strong></td><td>CapEx 是否與願景匹配</td><td>實質投資（廠房、設備、研發）→ ✅；無實際投入 → ❌</td></tr><tr><td style="text-align:left;"><strong>獲利能力</strong></td><td>毛利率/營業利率趨勢</td><td>產品組合升級帶動毛利提升 → ✅；毛利持平或下降 → ⚠️</td></tr><tr><td style="text-align:left;"><strong>管理執行力</strong></td><td>計畫 vs 實際達成率</td><td>按計畫執行（減資、擴產、股利）→ ✅；屢次跳票 → ❌</td></tr></tbody></table><h3 id="願景評級" tabindex="-1">願景評級 <a class="header-anchor" href="#願景評級" aria-label="Permalink to &quot;願景評級&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">評級</th><th>定義</th><th>估值影響</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>A（真實）</strong></td><td>四維度 ≥3✅，有明確財務數據支撐</td><td>可給予歷史中位數 +2~5x 溢價</td></tr><tr><td style="text-align:center;"><strong>B（部分真實）</strong></td><td>二維度✅，一維度⚠️，成長動能部分確認</td><td>適用歷史中位數，不給溢價</td></tr><tr><td style="text-align:center;"><strong>C（空洞敘事）</strong></td><td>零或一維度✅，無實質財務支撐</td><td>應以歷史低點估值，甚至折價</td></tr></tbody></table><h3 id="關鍵問題-「這是便宜的理由-還是壞掉的真相-」" tabindex="-1">關鍵問題：「這是便宜的理由，還是壞掉的真相？」 <a class="header-anchor" href="#關鍵問題-「這是便宜的理由-還是壞掉的真相-」" aria-label="Permalink to &quot;關鍵問題：「這是便宜的理由，還是壞掉的真相？」&quot;">​</a></h3><ul><li><strong>便宜的理由</strong>：景氣循環+成長週期，逢回檔可買</li><li><strong>壞掉的真相</strong>：結構性衰退，估值再低也不碰</li></ul><hr><h2 id="第四層-評價位階對位-valuation-anchoring" tabindex="-1">第四層：評價位階對位（Valuation Anchoring） <a class="header-anchor" href="#第四層-評價位階對位-valuation-anchoring" aria-label="Permalink to &quot;第四層：評價位階對位（Valuation Anchoring）&quot;">​</a></h2><h3 id="三指標交叉驗證" tabindex="-1">三指標交叉驗證 <a class="header-anchor" href="#三指標交叉驗證" aria-label="Permalink to &quot;三指標交叉驗證&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">估值指標</th><th style="text-align:right;">當前值</th><th style="text-align:right;">歷史中位數</th><th style="text-align:right;">溢價/折價幅度</th><th>解讀</th></tr></thead><tbody><tr><td style="text-align:left;">本益比 (PE)</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td>成長股核心指標</td></tr><tr><td style="text-align:left;">股價淨值比 (PBR)</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td>資產型公司參考</td></tr><tr><td style="text-align:left;">殖利率 (DY)</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td>收息型公司參考</td></tr></tbody></table><h3 id="估值百分位計算" tabindex="-1">估值百分位計算 <a class="header-anchor" href="#估值百分位計算" aria-label="Permalink to &quot;估值百分位計算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PER 百分位 = (當前 PER - 歷史最低 PER) ÷ (歷史最高 PER - 歷史最低 PER) × 100</span></span>
<span class="line"><span>PBR 百分位 = (當前 PBR - 歷史最低 PBR) ÷ (歷史最高 PBR - 歷史最低 PBR) × 100</span></span></code></pre></div><h3 id="百分位解讀" tabindex="-1">百分位解讀 <a class="header-anchor" href="#百分位解讀" aria-label="Permalink to &quot;百分位解讀&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">百分位區間</th><th>估值狀態</th><th>操作建議</th></tr></thead><tbody><tr><td style="text-align:center;">0-20th</td><td>極端低估</td><td>積極建倉區</td></tr><tr><td style="text-align:center;">20-50th</td><td>合理偏低</td><td>分批布局區</td></tr><tr><td style="text-align:center;">50-80th</td><td>合理偏高</td><td>觀望區</td></tr><tr><td style="text-align:center;">80-100th</td><td>極端高估</td><td>逢高減碼區</td></tr></tbody></table><h3 id="漲幅驅動因子拆解-進階" tabindex="-1">漲幅驅動因子拆解（進階） <a class="header-anchor" href="#漲幅驅動因子拆解-進階" aria-label="Permalink to &quot;漲幅驅動因子拆解（進階）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>總漲幅 = 基本面貢獻 + 估值擴張/壓縮貢獻</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例：股價從 A → B</span></span>
<span class="line"><span>- 基本面成長貢獻 = (EPS_B - EPS_A) ÷ EPS_A × 當前 PE</span></span>
<span class="line"><span>- 估值擴張貢獻 = (PE_B - PE_A) ÷ PE_A × 當前股價</span></span>
<span class="line"><span>- 驗證：基本面貢獻 + 估值擴張貢獻 ≈ 總漲幅（誤差 ±5%）</span></span></code></pre></div><p><strong>核心洞察</strong>：若估值擴張貢獻 &gt; 總漲幅的 40%，則回調風險大於上行空間。</p><hr><h2 id="第五層-決策執行建議-action-plan" tabindex="-1">第五層：決策執行建議（Action Plan） <a class="header-anchor" href="#第五層-決策執行建議-action-plan" aria-label="Permalink to &quot;第五層：決策執行建議（Action Plan）&quot;">​</a></h2><h3 id="操作等級" tabindex="-1">操作等級 <a class="header-anchor" href="#操作等級" aria-label="Permalink to &quot;操作等級&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">等級</th><th>定義</th><th>適用情境</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>A（買進）</strong></td><td>具安全邊際 + 願景真實 + 籌碼正面</td><td>分批建倉，目標價區間內</td></tr><tr><td style="text-align:center;"><strong>B+（持有）</strong></td><td>合理估值 + 願景部分真實</td><td>已持有者續抱，空手者觀望</td></tr><tr><td style="text-align:center;"><strong>B（持平）</strong></td><td>溢價估值 + 願景真實但已定價</td><td>逢高減碼，等待回檔</td></tr><tr><td style="text-align:center;"><strong>B-（觀望）</strong></td><td>極端溢價 + 願景部分真實</td><td>不宜追價，停損防線啟動</td></tr><tr><td style="text-align:center;"><strong>C（賣出）</strong></td><td>極端溢價 + 願景空洞 + 籌碼惡化</td><td>執行停損，尋找替代標的</td></tr></tbody></table><h3 id="買進區間設定規則" tabindex="-1">買進區間設定規則 <a class="header-anchor" href="#買進區間設定規則" aria-label="Permalink to &quot;買進區間設定規則&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">買區等級</th><th style="text-align:right;">PE 對應</th><th style="text-align:right;">安全邊際</th><th>適用條件</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一買區</strong></td><td style="text-align:right;">歷史高點附近 (20-25x)</td><td style="text-align:right;">低</td><td>需營收確認加速信號 + 籌碼正面</td></tr><tr><td style="text-align:center;"><strong>第二買區</strong></td><td style="text-align:right;">歷史中位數偏上 (15-20x)</td><td style="text-align:right;">中</td><td>具基本安全邊際，可分批布局</td></tr><tr><td style="text-align:center;"><strong>第三買區</strong></td><td style="text-align:right;">歷史中位數以下 (10-15x)</td><td style="text-align:right;">高</td><td>成長減速確認後的價值回歸點</td></tr></tbody></table><h3 id="停損防線設定" tabindex="-1">停損防線設定 <a class="header-anchor" href="#停損防線設定" aria-label="Permalink to &quot;停損防線設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">觸發條件</th><th>操作</th><th>理由</th></tr></thead><tbody><tr><td style="text-align:left;">跌破第一買區下緣（-15~20%）</td><td>減碼 30-50%</td><td>技術面轉弱，先降曝險</td></tr><tr><td style="text-align:left;">跌破第二買區下緣（-25~35%）</td><td>執行停損</td><td>成長預期遭破壞，估值修正確認</td></tr><tr><td style="text-align:left;">跌破第三買區下緣（-40%+）</td><td>全部出場</td><td>結構性問題，尋找替代標的</td></tr></tbody></table><h3 id="關鍵指標監控清單模板" tabindex="-1">關鍵指標監控清單模板 <a class="header-anchor" href="#關鍵指標監控清單模板" aria-label="Permalink to &quot;關鍵指標監控清單模板&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 指標 | 當前值 | 警戒線（下） | 警示線（上） |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|:---|---:|:---:|:---:|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| PER | — | &lt;15x（可布局） | &gt;25x（過熱） |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 月營收年增率 | — | &lt;5%（成長停滯） | — |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 毛利率(季) | — | &lt;XX%（產品組合惡化） | — |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 新業務佔比 | — | 持平或下降 | — |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 千張大戶佔比 | — | &lt;XX%（強勢手撤退） | — |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| 外資單週淨買賣超 | — | &lt; -XXX萬張（結構性撤退） | — |</span></span></code></pre></div><hr><h2 id="📊-綜合評級矩陣" tabindex="-1">📊 綜合評級矩陣 <a class="header-anchor" href="#📊-綜合評級矩陣" aria-label="Permalink to &quot;📊 綜合評級矩陣&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">風險壓力</th><th style="text-align:center;">估值位階</th><th style="text-align:center;">願景實現度</th><th style="text-align:center;">決策建議</th><th style="text-align:center;">綜合評級</th></tr></thead><tbody><tr><td style="text-align:center;">低風險</td><td style="text-align:center;">低估</td><td style="text-align:center;">A（真實）</td><td style="text-align:center;"><strong>A</strong>（買進）</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">低風險</td><td style="text-align:center;">低估</td><td style="text-align:center;">B（部分真實）</td><td style="text-align:center;"><strong>A</strong>（買進）</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">低風險</td><td style="text-align:center;">合理</td><td style="text-align:center;">A（真實）</td><td style="text-align:center;"><strong>B+</strong>（持有）</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">中風險</td><td style="text-align:center;">合理</td><td style="text-align:center;">A（真實）</td><td style="text-align:center;"><strong>B+</strong>（持有）</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">中風險</td><td style="text-align:center;">溢價</td><td style="text-align:center;">A（真實）</td><td style="text-align:center;"><strong>B</strong>（觀望）</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">高風險</td><td style="text-align:center;">溢價</td><td style="text-align:center;">B（部分真實）</td><td style="text-align:center;"><strong>B-</strong>（觀望）</td><td style="text-align:center;">⭐⭐</td></tr><tr><td style="text-align:center;">高風險</td><td style="text-align:center;">極端溢價</td><td style="text-align:center;">C（空洞）</td><td style="text-align:center;"><strong>C</strong>（賣出）</td><td style="text-align:center;">⭐</td></tr></tbody></table><hr><h2 id="🔧-實作檢查清單-checklist" tabindex="-1">🔧 實作檢查清單（Checklist） <a class="header-anchor" href="#🔧-實作檢查清單-checklist" aria-label="Permalink to &quot;🔧 實作檢查清單（Checklist）&quot;">​</a></h2><p>每次執行 F18 審計時，依序完成：</p><ul><li>[ ] <strong>第0步</strong>：收集基礎數據（股價、EPS、營收、籌碼面）</li><li>[ ] <strong>第1步</strong>：計算歷史 PE 區間（3-5年）與當前估值百分位</li><li>[ ] <strong>第2步</strong>：執行五情境壓力測試，繪製合理估值區間</li><li>[ ] <strong>第3步</strong>：四維度願景審核（成長動能、CapEx、毛利率、管理執行力）</li><li>[ ] <strong>第4步</strong>：三指標交叉驗證（PE、PBR、DY）</li><li>[ ] <strong>第5步</strong>：漲幅驅動因子拆解（基本面 vs 估值擴張）</li><li>[ ] <strong>第6步</strong>：綜合評級判定（風險 × 估值 × 願景）</li><li>[ ] <strong>第7步</strong>：輸出操作等級、買區建議、停損防線</li><li>[ ] <strong>第8步</strong>：建立關鍵指標監控清單</li></ul><hr><h2 id="📚-參考實例" tabindex="-1">📚 參考實例 <a class="header-anchor" href="#📚-參考實例" aria-label="Permalink to &quot;📚 參考實例&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">股票</th><th style="text-align:center;">報告日期</th><th>關鍵發現</th></tr></thead><tbody><tr><td style="text-align:left;">良維</td><td style="text-align:center;">6290</td><td style="text-align:center;">2026-04-24</td><td>PE 35.1x 創3年新高，合理區間 130-175元（PE 15-20x），評級 B</td></tr><tr><td style="text-align:left;">瀚荃</td><td style="text-align:center;">8103</td><td style="text-align:center;">2026-04-25</td><td>PE 24.0x 歷史極端，合理區間 65-85元（PE 15-19x），評級 B</td></tr></tbody></table><hr><p><em>框架設計：Deep32Q 投資研究員團隊 | 基於良維(6290)、瀚荃(8103)實例提煉 | 持續更新中</em></p><blockquote><p><strong>⚠️ 免責聲明</strong>：本框架為結構化財務分析方法論，內容僅供參考，不構成任何買賣建議。投資決策應基於個人風險承受能力與完整盡職調查。</p></blockquote>`,62)])])}const x=e(s,[["render",d]]);export{p as __pageData,x as default};
